code = """import json, pandas as pd

reviews = pd.DataFrame(var_call_k2wvATXWiffFrhUcNbWbfaPD)
biz = pd.DataFrame(var_call_yWocxfe6qzwHFRmVdZlvVpBW)

# normalize types
reviews['review_cnt'] = reviews['review_cnt'].astype(int)

# map businessref_X -> businessid_X to join
reviews['business_id'] = reviews['business_ref'].str.replace('businessref_', 'businessid_', regex=False)

# extract categories from biz if present; if missing, treat as Unknown
if 'categories' not in biz.columns:
    biz['categories'] = None

# make categories list
cat_rows = []
for _, row in biz.iterrows():
    bid = row.get('business_id')
    cats = row.get('categories')
    if cats is None:
        cat_rows.append((bid, 'Unknown'))
    elif isinstance(cats, list):
        if len(cats)==0:
            cat_rows.append((bid, 'Unknown'))
        else:
            for c in cats:
                cat_rows.append((bid, str(c)))
    else:
        # if it's a comma-separated string
        s = str(cats)
        parts = [p.strip() for p in s.split(',') if p.strip()]
        if not parts:
            cat_rows.append((bid, 'Unknown'))
        else:
            for c in parts:
                cat_rows.append((bid, c))

cat_df = pd.DataFrame(cat_rows, columns=['business_id','category'])

merged = reviews.merge(cat_df, on='business_id', how='left')
merged['category'] = merged['category'].fillna('Unknown')

agg = merged.groupby('category', as_index=False)['review_cnt'].sum().sort_values('review_cnt', ascending=False)

top5 = agg.head(5)
result = top5.to_dict(orient='records')

print('__RESULT__:')
print(json.dumps(result))"""

